```go server/internal/app/config.go
package config

import (
	"fmt"
	"os"
	"strconv"
	"time"

	"github.com/joho/godotenv"
)

// Config holds all application configuration
type Config struct {
	Server   ServerConfig
	Database DatabaseConfig
	Paseto   PasetoConfig
	Cookie   CookieConfig
}

// ServerConfig holds HTTP server configuration
type ServerConfig struct {
	Host string
	Port string
}

// DatabaseConfig holds database connection settings
type DatabaseConfig struct {
	Host     string
	Port     string
	User     string
	Password string
	DBName   string
	SSLMode  string
}

// PasetoConfig holds PASETO token configuration
type PasetoConfig struct {
	SymmetricKey         string
	AccessTokenDuration  time.Duration
	RefreshTokenDuration time.Duration
}

// CookieConfig holds cookie configuration
type CookieConfig struct {
	Domain   string
	Secure   bool
	HTTPOnly bool
	MaxAge   time.Duration
	SameSite string // Added for modern cookie security
}

// DSN returns the database connection string
func (db *DatabaseConfig) DSN() string {
	return fmt.Sprintf(
		"host=%s port=%s user=%s password=%s dbname=%s sslmode=%s",
		db.Host, db.Port, db.User, db.Password, db.DBName, db.SSLMode,
	)
}

// LoadConfig loads configuration from environment variables
func LoadConfig() (*Config, error) {
	// Load .env file only in development mode
	if os.Getenv("APP_ENV") != "production" {
		if err := godotenv.Load(); err != nil {
			// Just log the error but continue, as env vars might be set through other means
			fmt.Printf("Warning: error loading .env file: %v\n", err)
		}
	}

	// Helper function to get env var with default value
	getEnv := func(key, defaultValue string) string {
		if value, exists := os.LookupEnv(key); exists {
			return value
		}
		return defaultValue
	}

	// Helper function to parse boolean env var
	parseBool := func(key string, defaultValue bool) bool {
		valStr := getEnv(key, fmt.Sprintf("%t", defaultValue))
		val, err := strconv.ParseBool(valStr)
		if err != nil {
			return defaultValue
		}
		return val
	}

	// Helper function to parse time.Duration from seconds
	parseDuration := func(key string, defaultSeconds int) time.Duration {
		valStr := getEnv(key, fmt.Sprintf("%d", defaultSeconds))
		val, err := strconv.Atoi(valStr)
		if err != nil {
			return time.Duration(defaultSeconds) * time.Second
		}
		return time.Duration(val) * time.Second
	}

	return &Config{
		Server: ServerConfig{
			Host: getEnv("SERVER_HOST", "0.0.0.0"),
			Port: getEnv("SERVER_PORT", "8080"),
		},
		Database: DatabaseConfig{
			Host:     getEnv("DB_HOST", "localhost"),
			Port:     getEnv("DB_PORT", "5432"),
			User:     getEnv("DB_USER", "postgres"),
			Password: getEnv("DB_PASSWORD", ""),
			DBName:   getEnv("DB_NAME", "postgres"),
			SSLMode:  getEnv("DB_SSLMODE", "disable"),
		},
		Paseto: PasetoConfig{
			SymmetricKey:         getEnv("PASETO_SYMMETRIC_KEY", ""),
			AccessTokenDuration:  parseDuration("ACCESS_TOKEN_DURATION", 15*60),     // Default 15 minutes
			RefreshTokenDuration: parseDuration("REFRESH_TOKEN_DURATION", 24*60*60), // Default 24 hours
		},
		Cookie: CookieConfig{
			Domain:   getEnv("COOKIE_DOMAIN", ""),
			Secure:   parseBool("COOKIE_SECURE", true),
			HTTPOnly: parseBool("COOKIE_HTTP_ONLY", true),
			MaxAge:   parseDuration("COOKIE_MAX_AGE_SECS", 24*60*60), // Default 24 hours
			SameSite: getEnv("COOKIE_SAME_SITE", "Lax"),              // Modern browsers use this
		},
	}, nil
}

// Validate checks if the configuration is valid
func (c *Config) Validate() error {
	if c.Paseto.SymmetricKey == "" {
		return fmt.Errorf("PASETO_SYMMETRIC_KEY is required")
	}

	// Add other validation as needed

	return nil
}
